cat <<'EOF' | agent-browser eval --stdin 2>&1
// Collect console errors via window.__consoleErrors if available, else check for JS errors
const errors = window.__browserQAErrors || [];
const title = document.title;
const h1 = document.querySelector('h1')?.textContent?.trim();
const mainLandmark = !!document.querySelector('main, [role="main"]');
const skipLink = document.querySelector('a[href^="#"]')?.textContent?.trim();
const images = Array.from(document.images);
const brokenImages = images.filter(img => !img.complete || img.naturalWidth === 0).map(img => img.src.slice(0, 80));
const altMissing = images.filter(img => img.closest('picture') ? false : (!img.alt && img.naturalWidth > 0)).length;
({title, h1, mainLandmark, skipLink, brokenImages, altMissing, totalImages: images.length})
EOF

cat <<'EOF' | agent-browser eval --stdin 2>&1
// More precise broken image check - check complete + naturalWidth properly
const images = Array.from(document.images);
const broken = images.filter(img => {
  // Only flag if completely loaded but has no dimensions (not lazy-load placeholders)
  if (!img.complete) return false;
  if (img.naturalWidth === 0 && img.src && !img.src.startsWith('data:') && img.src !== '') return true;
  return false;
});
({
  broken: broken.slice(0, 10).map(img => ({src: img.src, complete: img.complete, naturalWidth: img.naturalWidth})),
  brokenCount: broken.length,
  total: images.length
})
EOF

cat <<'EOF' | agent-browser eval --stdin 2>&1
// Check for actual console errors by looking at error overlay / any visible error state
// Also check for missing alt text more carefully (exclude decorative img with empty alt)
const images = Array.from(document.images);
const missingAlt = images.filter(img => img.alt === null || img.alt === undefined);
const emptyAlt = images.filter(img => img.alt === ''); // decorative, OK
const hasAlt = images.filter(img => img.alt && img.alt.trim() !== '').length;
// Check for keyboard skip link functionality
const skipLink = document.querySelector('a[href="#main_focusable"], a[href^="#main"]');
({
  imagesWithAlt: hasAlt,
  imagesWithEmptyAlt: emptyAlt.length,
  imagesWithNullAlt: missingAlt.length,
  skipLinkHref: skipLink?.href,
  skipLinkText: skipLink?.textContent?.trim()
})
EOF

cat <<'EOF' | agent-browser eval --stdin 2>&1
const imgs = Array.from(document.images);
const broken = imgs.filter(img => img.complete && img.naturalWidth === 0 && img.src && !img.src.startsWith('data:') && img.src !== '');
({brokenCount: broken.length, total: imgs.length, sample: broken.slice(0,3).map(i => i.src)})
EOF

# Check alt text issue more carefully
cat <<'EOF' | agent-browser eval --stdin 2>&1
const imgs = Array.from(document.images);
const missingAlt = imgs.filter(img => img.getAttribute('alt') === null);
const emptyAlt = imgs.filter(img => img.getAttribute('alt') === '');
const hasAlt = imgs.filter(img => img.getAttribute('alt') && img.getAttribute('alt').trim() !== '');
({
  missingAlt: missingAlt.length,
  emptyAlt: emptyAlt.length,
  hasAlt: hasAlt.length,
  total: imgs.length,
  missingAltSamples: missingAlt.slice(0,5).map(i => i.src.split('/').slice(-1)[0])
})
EOF

cat <<'JSEOF' | agent-browser eval --stdin 2>&1
(() => {
  const allImgs = Array.from(document.images);
  const missing = allImgs.filter(img => img.getAttribute('alt') === null);
  const empty = allImgs.filter(img => img.getAttribute('alt') === '');
  const hasText = allImgs.filter(img => img.getAttribute('alt') && img.getAttribute('alt').trim() !== '');
  return {missingAlt: missing.length, emptyAlt: empty.length, hasAlt: hasText.length, total: allImgs.length, missingAltSamples: missing.slice(0,5).map(i => i.src.split('/').slice(-1)[0])};
})()
JSEOF

cat <<'JSEOF' | agent-browser eval --stdin 2>&1
(() => {
  // Check for obvious layout issues: overflow
  const body = document.body;
  const htmlEl = document.documentElement;
  const bodyWidth = body.scrollWidth;
  const viewportWidth = window.innerWidth;
  const hasHorizOverflow = bodyWidth > viewportWidth;
  // Check for elements protruding beyond viewport
  const allEls = document.querySelectorAll('main *, header *');
  const overflowing = Array.from(allEls).filter(el => {
    const rect = el.getBoundingClientRect();
    return rect.right > viewportWidth + 5;
  }).slice(0,3).map(el => ({tag: el.tagName, class: el.className?.slice(0,40)}));
  return {bodyWidth, viewportWidth, hasHorizOverflow, overflowingSamples: overflowing};
})()
JSEOF

